<template>
    <div>
        <h1>设置</h1>
        <br />
        <el-switch
            v-model="isDark"
            class="mt-2"
            style="margin-left: 24px"
            inline-prompt
            :active-icon="Moon"
            :inactive-icon="Sunny"
        />
    </div>
</template>

<script setup>
import { Sunny, Moon } from "@element-plus/icons-vue";
import { useStore } from "vuex";
import { computed, ref, watch } from "vue";

const store = useStore();

const isDark = ref(false);
watch(
    () => store.state.isDark,
    val => {
        isDark.value = val;
        console.log(val);
    },
    {
        immediate: true
    }
);

watch(isDark, val => {
    store.commit("useDark", val);
});
</script>

<style scoped></style>
